// Solution
function validateRoutePath(path) {
  if (path.indexOf(':') === -1) return true;
  const regex = //users/([a-zA-Z0-9]{1,20})/posts/([a-zA-Z0-9]{1,20})/;
  const result = regex.exec(path);
  if (result === null) return false;
  const username = result[1];
  const postId = result[2];
  return /^[a-zA-Z0-9]+$/.test(username) && /^[a-zA-Z0-9]+$/.test(postId);
}
